import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

const BusinessDetails = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { squareNumber, duration, pageNumber } = location.state || {};
  
  const [businessName, setBusinessName] = useState('');
  const [contactEmail, setContactEmail] = useState('');
  const [dealLink, setDealLink] = useState('');
  const [logoData, setLogoData] = useState(null);
  const [isFormValid, setIsFormValid] = useState(false);

  // Enhanced validation with detailed logging
  const validateForm = () => {
    const hasBusinessName = businessName.trim() !== '';
    const hasContactEmail = contactEmail.trim() !== '';
    const hasLogo = logoData !== null;
    
    const isValid = hasBusinessName && hasContactEmail && hasLogo;
    
    console.log('🔍 VALIDATION CHECK:', {
      businessName: businessName,
      hasBusinessName: hasBusinessName,
      contactEmail: contactEmail,
      hasContactEmail: hasContactEmail,
      logoData: logoData ? 'EXISTS' : 'MISSING',
      hasLogo: hasLogo,
      isValid: isValid
    });
    
    setIsFormValid(isValid);
  };

  const previewLogo = (event) => {
    const file = event.target.files[0];
    console.log('📁 File selected:', file);
    
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert('File size must be less than 2MB');
        return;
      }
      
      const reader = new FileReader();
      reader.onload = function(e) {
        console.log('✅ Logo loaded successfully, data length:', e.target.result.length);
        setLogoData(e.target.result);
        validateForm();
      }
      
      reader.onerror = function(e) {
        console.error('❌ Error reading file:', e);
      }
      
      reader.readAsDataURL(file);
    } else {
      console.log('❌ No file selected');
    }
  };

  const handleContinue = () => {
    console.log('🎯 Continue button clicked, isFormValid:', isFormValid);
    
    if (!isFormValid) {
      alert('Please complete all required fields: Business Name, Email, and Logo Upload');
      return;
    }

    const purchaseData = {
      squareNumber,
      duration,
      pageNumber,
      businessName,
      contactEmail,
      dealLink: dealLink || `https://${businessName.toLowerCase().replace(/\s+/g, '')}.com/deals`,
      logoData
    };
    
    console.log('🚀 Navigating to checkout with:', purchaseData);
    navigate('/checkout', { state: purchaseData });
  };

  const totalAmount = duration;

  return (
    <div className="checkout-container">
      <div className="checkout-header">
        <h1>🛍️ Business & Advertisement Details</h1>
        <p>Complete your advertising campaign setup</p>
      </div>

      <div className="checkout-content">
        {/* Order Summary */}
        <div className="order-summary">
          <h3>📋 Order Summary</h3>
          <div className="summary-details">
            <div className="summary-item">
              <span>Square Number:</span>
              <strong>#{squareNumber}</strong>
            </div>
            <div className="summary-item">
              <span>Page:</span>
              <strong>Page {pageNumber}</strong>
            </div>
            <div className="summary-item">
              <span>Duration:</span>
              <strong>{duration} days</strong>
            </div>
            <div className="summary-item">
              <span>Daily Rate:</span>
              <strong>£1.00/day</strong>
            </div>
            <div className="summary-item total">
              <span>Total Amount:</span>
              <strong>£{totalAmount}.00</strong>
            </div>
          </div>
        </div>

        {/* Business Form */}
        <div className="business-form">
          <div className="form-section">
            <h3>🏢 Business Information</h3>
            
            <div className="form-group">
              <label htmlFor="businessName">Business Name *</label>
              <input 
                type="text" 
                id="businessName"
                name="businessName" 
                placeholder="Enter your business name"
                value={businessName}
                onChange={(e) => {
                  setBusinessName(e.target.value);
                  console.log('📝 Business name changed:', e.target.value);
                  validateForm();
                }}
                autoComplete="organization"
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="contactEmail">Contact Email *</label>
              <input 
                type="email" 
                id="contactEmail"
                name="email" 
                placeholder="Enter your email address"
                value={contactEmail}
                onChange={(e) => {
                  setContactEmail(e.target.value);
                  console.log('📧 Email changed:', e.target.value);
                  validateForm();
                }}
                autoComplete="email"
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="dealLink">Deal/Discount Page URL (Optional)</label>
              <input 
                type="url" 
                id="dealLink"
                name="dealLink" 
                placeholder="https://yourwebsite.com/deals"
                value={dealLink}
                onChange={(e) => setDealLink(e.target.value)}
                autoComplete="url"
              />
              <small>Where customers will be directed when they click your logo</small>
            </div>
          </div>

          <div className="form-section">
            <h3>🖼️ Company Logo *</h3>
            
            <div className="form-group">
              <label htmlFor="logoUpload">Upload Logo *</label>
              <input 
                type="file" 
                id="logoUpload"
                name="logo" 
                accept="image/*"
                onChange={previewLogo}
                autoComplete="off"
              />
              <small>PNG, JPG up to 2MB. Required to continue.</small>
            </div>

            {logoData && (
              <div className="logo-preview">
                <h4>✅ Logo Uploaded Successfully!</h4>
                <img src={logoData} alt="Logo preview" style={{maxWidth: '200px', maxHeight: '200px'}} />
                <p style={{color: 'green', fontWeight: 'bold'}}>Logo ready! You can continue to payment.</p>
              </div>
            )}
          </div>

          {/* Enhanced Debug Info */}
          <div style={{
            background: '#fff3cd', 
            padding: '15px', 
            borderRadius: '5px', 
            margin: '15px 0',
            border: '1px solid #ffeaa7'
          }}>
            <h4>🔧 Debug Information:</h4>
            <div style={{fontFamily: 'monospace', fontSize: '12px'}}>
              <div>Form Valid: <strong>{isFormValid ? '✅ YES' : '❌ NO'}</strong></div>
              <div>Business Name: <strong>{businessName ? `"${businessName}" ✅` : '❌ MISSING'}</strong></div>
              <div>Contact Email: <strong>{contactEmail ? `"${contactEmail}" ✅` : '❌ MISSING'}</strong></div>
              <div>Logo Uploaded: <strong>{logoData ? '✅ YES' : '❌ NO'}</strong></div>
              <div>Deal Link: <strong>{dealLink ? `"${dealLink}"` : 'Optional'}</strong></div>
            </div>
          </div>

          <div className="form-actions">
            <button 
              type="button" 
              className="btn-secondary" 
              onClick={() => navigate(-1)}
              style={{
                background: '#6c757d',
                color: 'white',
                padding: '12px 24px',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                marginRight: '10px'
              }}
            >
              ← Back
            </button>
            <button 
              type="button" 
              onClick={handleContinue}
              disabled={!isFormValid}
              style={{
                background: isFormValid ? '#28a745' : '#6c757d',
                color: 'white',
                padding: '12px 24px',
                border: 'none',
                borderRadius: '6px',
                cursor: isFormValid ? 'pointer' : 'not-allowed',
                fontWeight: 'bold'
              }}
            >
              {isFormValid ? "🚀 Continue to Payment →" : "⏳ Complete Form to Continue"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BusinessDetails;
